var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좌표도, 방향도 틀림없는데……","JPN":"座標も、方向も間違いないのに……","ENG":"The directions and the coordinates should be correct...","TWN":"座標、方向也都沒錯……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 뭐 좀 보이나요?","JPN":"ルナさん、何か見えますか？","ENG":"Luna, do you see anything?","TWN":"露娜，看見什麼了嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어디를 봐도 새하얀 구름에 시퍼런 바다뿐이야.","JPN":"どこを見ても真っ白な雲に真っ青な海だけだよ。","ENG":"Everywhere I look, it's all white clouds on top and blue water below.","TWN":"不管怎麼看，都是潔白的雲彩和蔚藍的大海。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지도에는 없는 섬이라니, 혹시 우리 그 할배한테 깜빡 속은 거 아냐?","JPN":"地図にはない島って。もしかしてアタシたち、あのジジイに騙されたんじゃない？","ENG":"An island that's not on the map... Did that geezer trick us?","TWN":"地圖上不存在的小島，我們不會被那個老爺爺給騙了吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위치는 제대로 말해 줬네만, 배를 모는 기술은 다른 문제지.","JPN":"位置はしっかりと教えてくれても、船を操る技術はまた別の問題さ。","ENG":"He gave us the right coordinates, but perhaps it's more about our ability to sail.","TWN":"位置已經說清楚了，但開船的技術就另當別論了。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양이 나침반을 잘못 보는 순간 우리 모두 표류자 신세가 될 수도 있다네.","JPN":"マクレディー君がコンパスを見間違えた瞬間、我々全員が漂流者になり得る。","ENG":"We'll all be castaways the moment Regina misreads the compass.","TWN":"如果麥克蕾蒂看錯指南針，我們可能就都得隨波漂流了。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그, 그럼 저희 모두 전설 속 유령선처럼 백골이 된 뒤에도 영원히 바다를 떠도는 건가요?","JPN":"そ、それじゃ私たちはみんな、伝説の中の幽霊船のように白骨になっても永遠に海を彷徨うんですか？","ENG":"D-does that mean we'll end up like the ghosts from legends that wander the sea for eternity?","TWN":"那裂隙那我們會像傳說中的幽靈船一樣，變成白骨後還永遠在海上漂泊嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜한 소리에 무서워하지 마세요, 실키.","JPN":"ばかばかしい話に怖がらないでください、シルキー。","ENG":"Do not get scared by his words, Sylkie.","TWN":"你別聽他胡說，思琪。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 유령선은 대항해시대 때 무풍지대에서 조난당한 범선들에서 기원한 이야기입니다.","JPN":"それに、幽霊船は大航海時代に無風地帯で遭難した帆船から始まった物語ですわ。","ENG":"Also, ghost ship stories originated from ships that became stranded in the Sargasso Sea during the Age of Discovery.","TWN":"還有，幽靈船的故事起源於大航海時代在無風地帶遇難的船隻。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"동력기관으로 항해할 수 있는 현대의 배에는 통용되지 않아요.","JPN":"動力機関で航海する現代の船には通用しません。","ENG":"The phrase is therefore no longer relevant given the engines of modern ships.","TWN":"不適用於可以用動力機械航行的現代船隻。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇군요……","JPN":"そうなんですね……","ENG":"I see...","TWN":"這樣啊……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만 죽은 뒤에도 부학회장님을 모실 수 있다면, 그것도 나쁘지 않을 것 같아요.","JPN":"でも死んだ後も副学会長様に仕えられるなら、それも悪くないと思います。","ENG":"But if I can still be your caregiver in the afterlife, I don't think it'll be that bad.","TWN":"不過如果死了以後也能服侍副學會長的話，那好像也不錯。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어…… 우선 죽지 않을 생각부터 해 주시겠어요?","JPN":"えーっと……まずは死なないことから考えてくれますか？","ENG":"Uh... How about we consider not dying first?","TWN":"呃……你可以先想想怎樣能不死嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"앗, 부학회장! 북쪽에 뭔가 보여!","JPN":"あっ、副学会長！　北の方に何か見える！","ENG":"Oh! Vice President! I see something up north!","TWN":"啊，副學會長！北邊有什麼東西！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"배는 아닌 것 같은데…… 정말 섬인가?","JPN":"船じゃないみたいだけど……本当に島なのかな？","ENG":"It's not a boat... Is it really an island?","TWN":"好像不是船……真的是小島嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"확인해 볼 가치는 있겠네요. 우선 갑판으로 돌아오세요.","JPN":"確認してみる価値はありそうですわね。まずはデッキに戻ってください。","ENG":"It might be worth checking out. Come back down to the deck.","TWN":"值得確認一下。先回到甲板上來吧。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"기관의 본거지라니…… 각오를 단단히 해야겠네요.","JPN":"機関の本拠地……しっかり覚悟しないとダメですね。","ENG":"The headquarters of the Institution... I guess we should brace ourselves.","TWN":"機關的大本營……看來要做好心理準備了。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어쩌면 입구에 사람 머리 가죽을 걸어 놓고 있을지도 몰라요.","JPN":"もしかしたら入口に人の頭皮をつるしてあるかもしれません。","ENG":"They may even have human heads hanging at the entrance...","TWN":"說不定門口就掛著人的頭皮呢。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그럴 일 없어요.","JPN":"……そんなはずはありませんわ。","ENG":"…That\xA0won't\xA0happen.","TWN":"……沒有那種事。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"헤에, 화산섬에 이런 커다란 시설을 만들어서 쓰고 있었구나.","JPN":"へぇ、火山島にこんな大きな施設を建てて使ってたんだ。","ENG":"Hmm? So they made this entire volcanic island into a base.","TWN":"嘿，居然在火山島上建造了這麼大的設施來使用。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"기관 녀석들, 이번에 뒤통수가 좀 얼얼하겠는데.","JPN":"機関のやつら、今回は結構ショックを受けるかもね。","ENG":"Those Institution jerks. I bet they got what they deserved.","TWN":"機關那些人，這次應該栽了個大跟斗吧。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 저게 학회가 찾던 호수의 파편인가요?","JPN":"副学会長様、あれが学会が探していた湖の破片ですか？","ENG":"Ms. Vice President, is this the Fragment the Society is looking for?","TWN":"副學會長，那個是學會一直在找的湖水碎片嗎？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"큰 언니에게 들었어요. 저 안에 무궁무진한 지식의 신비가 감춰져 있는 거죠? 굉장해요!","JPN":"上の姉から聞きました。あの中には無限なる知識の神秘が秘められているんですよね？　すごいです！","ENG":"My sister told me that it contains an infinite amount of knowledge and secrets. Isn't that incredible?","TWN":"我聽大姊說過，那裡面蘊藏著無窮無盡的知識奧秘？太厲害了！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"감춰져 있기야 하겠지만 그걸 제대로 써먹을 수 있을지는 별개라구.","JPN":"秘められてはいるだろうけど、それをちゃんと使えるかどうかは別の問題だよ。","ENG":"Even if it's hidden, knowing how to use it properly is a different story altogether.","TWN":"雖然蘊藏很多奧秘，但如何利用就是另外一回事了。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"원래 복잡한 기술일수록 기반 지식 없이는 이해 못하거든.","JPN":"そもそも複雑な技術ほど、基盤になる知識なしでは理解できないから。","ENG":"The more complicated the technology, the more difficult it is to grasp without a solid foundation.","TWN":"越是複雜的技術，沒有基礎知識的積累就越難理解。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"학회에서 열심히 연구하시는 분들이 계시잖아요.","JPN":"学会で一生懸命研究されている方々がいるじゃないですか。","ENG":"But that's what the people at the Society are doing, right?","TWN":"學會不是有很多努力研究的人嘛。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"영지에 이 소식이 전해지면 모두들 축하해 줄 거예요.","JPN":"領地の人がこの知らせを聞けば、みなさんお祝いしてくれますよ。","ENG":"I'm sure everyone will be overjoyed if we bring this news back to the estate.","TWN":"這個消息傳到領地的話，大家都會祝賀的。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님은 기쁘지 않으세요?","JPN":"副学会長様は嬉しくないですか？","ENG":"Aren't you also thrilled, ma'am?","TWN":"副學會長，你不開心嗎？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 배를 타고 여기까지 오는 동안 아무도 저희를 붙잡지 않았습니다.","JPN":"ええ。船に乗ってここまで来る途中、誰も私たちを引き止めませんでした。","ENG":"Yes. I am thrilled that no one has captured us on our way here.","TWN":"是啊，我們開船一路過來，沒有任何人阻攔。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"게다가……","JPN":"それに……","ENG":"Besides...","TWN":"而且……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죽은 사람들이 수도 없이 많아요. 기관 소속 사람들도, 학회원들도.","JPN":"数えきれないほどの人が亡くなっています。機関の人も、学会員も。","ENG":"Countless people have died. People of the Institution and the Society.","TWN":"還死了很多人。有機關的人，也有學會成員。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……포기하는 편이 나았을지도 모르는데, 마지막까지 분전하였군.","JPN":"……あきらめた方がましだったかもしれないのに、最後まで奮戦したんだな。","ENG":"…It might have been better to surrender, but they fought until the bitter end.","TWN":"……或許放棄會更好，但還是奮戰到了最後啊。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭐, 부질없는 저항이었겠지. 아무리 그래도 마왕님이 상대인데.","JPN":"まあ、無駄な抵抗だったんでしょ。いくらなんでも相手は魔王だし。","ENG":"Well, their resistance was futile. I mean, they're going up against a Demon Lord.","TWN":"嗯，應該都是無謂的抵抗吧。再怎麼說，對手可是魔王。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"으윽, 으으……","JPN":"ううっ、うう……","ENG":"Ngh... Eergh...","TWN":"呃啊，呃呃……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_08"},{"id":"L5_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"끼야아악!","JPN":"きゃああっ！","ENG":"Kyaaaah!","TWN":"哎呀媽呀！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"깜짝이야! 갑자기 웬 비명이에요?!","JPN":"驚かせないでください！　いきなり悲鳴をあげるとはなにごとですか！？","ENG":"Huh?! Who just screamed?!","TWN":"嚇我一跳！你幹嘛突然尖叫？！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"시시시체를 건드렸더니 갑자기 신음을!","JPN":"ししし死体に触れたらいきなりうめいて！","ENG":"I-I touched one and it started groaning!","TWN":"我碰了一下屍體，結果他卻突然發出了呻吟聲！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"좀비 아냐?! 부적 같은 거 없어?! 소금이라거나!","JPN":"ゾンビじゃない！？　御札とかないの！？　塩とか！","ENG":"It's not a zombie, right?! D-do you have any charms?! O-or w-what about some salt?!!","TWN":"不會是僵屍吧？！有沒有符咒？或者鹽之類的！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"생존자잖아요! 호들갑 떨지 말고 진정해요!","JPN":"生き残りでしょう！　騒がないで落ち着きなさい！","ENG":"Stop overreacting! She must be a survivor.","TWN":"不就是倖存者嘛！你別大驚小怪的，冷靜點！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"윽…… 으윽……","JPN":"うっ……ぐっ……","ENG":"Ngh... Ugh...","TWN":"呃……呃呃……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"제, 제발…… 목숨만은…… 목숨만 살려 주세요. 살려 주시면 뭐든 하겠습니다……!","JPN":"ど、どうか……命だけは……見逃してください。そしたら何でもします……！","ENG":"P-please... D-don't kill me... I beg you. I'll do anything...!","TWN":"救…救……救救我……救命啊，救救我，我什麼都願意做……！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"안심하세요. 저희는 당신을 해칠 생각이 없습니다.","JPN":"安心してください。私たちはあなたを傷つけるつもりはありませんわ。","ENG":"Rest assured. We are not here to hurt you.","TWN":"你放心，我們不會傷害你。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아니, 그럼 어쩌게? 약 바르고 붕대라도 감아 주려고?","JPN":"え～、じゃあどうするの？　薬塗って包帯でもまいてあげるの？","ENG":"Huh? Then what are you going to do? Treat her wounds and bandage her up?","TWN":"可是你想怎麼辦？給他上藥，然後纏上繃帶嗎？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 부상을 입으신 모양이에요. 우선 안전한 곳으로 옮겨야겠습니다.","JPN":"はい。怪我をされているようですね。まずは安全なところまで運びましょう。","ENG":"Yes. She is badly wounded. We should first move her to some place safe.","TWN":"嗯，他好像受傷了。我們先把他帶到安全的地方吧。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이렇게 큰 시설이라면, 멀지 않은 거리에 의무실도──","JPN":"これほど大きな施設なら、遠くないところに医務室も……","ENG":"With a facility this big, there must be a medic bay nea–","TWN":"這麼大的設施，附近應該有醫務室——"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장님, 총성이야! 총성!","JPN":"副学会長、銃声だよ！　銃声！","ENG":"Whoa! That was a gunshot! A GUNSHOT!","TWN":"副學會長，是槍聲！槍聲！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저도 들었어요. 기관 사람들이 아직 남아 있나 봐요.","JPN":"私も聞きました。まだ機関の人たちが残っているんでしょう。","ENG":"I heard it too. Maybe some of the Institution people are still alive.","TWN":"我也聽見了。看來還有機關的人。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"간격이 뜸하군. 기관 측이 아직 전투를 치를 수 있다면 이 정도는 아닐 걸세.","JPN":"間隔が長い。機関側がまだ戦闘できる状態なら、この程度ではすまないだろう。","ENG":"The shots are infrequent. It wouldn't be like this if they were still engaged in combat.","TWN":"不過這種零星槍聲，如果是機關方面還能戰鬥的話，應該不止這種程度。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 교전 중이라기에는 너무 간헐적으로 들려요.","JPN":"はい。交戦中にしてはあまりにも断続的です。","ENG":"Yes. I doubt that they are still in combat as well.","TWN":"是啊，要說還在交戰，槍聲的密度太稀疏了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"게다가…… 점점 가까워지고 있습니다.","JPN":"それに……どんどん近づいてきていますわ。","ENG":"But also... The sound is getting closer.","TWN":"而且……好像正在慢慢靠近。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"확인 사살이라니 솔선수범의 표본 같은 분이네.","JPN":"確認射殺なんて、率先垂範のお手本のような方ね。","ENG":"You're like a leading example of how to confirm kills.","TWN":"確認擊斃，你簡直就是身先士卒的表率。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이런 번거로운 일은 그냥 부하들에게 맡기는 편이 낫지 않아, 소장님?","JPN":"こんな面倒くさいことは部下に任せた方がよくないかしら、所長。","ENG":"But wouldn't it be better to leave the tedious tasks to one of your men instead, Chief Heydrich?","TWN":"這種麻煩事直接交給手下人去做不是更好嗎，所長？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"내가 만든 병기들이 전쟁에서 요구하는 모든 임무를 수행할 수 있을지 확인하고 싶을 뿐이오.","JPN":"私が作った兵器が戦争で求められるすべての任務を遂行できるか、確認したいだけだ。","ENG":"I want to see for myself that the weapon I designed did everything I asked of it.","TWN":"我只是想確認一下，我做出來的武器能否在戰爭中勝任各種任務。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그리고 그 중에는 현장에 나오지 않으면 평가할 수 없는 종류도 존재하지.","JPN":"そしてその中には現場に出ないと評価できない種類も存在する。","ENG":"And among them, there are some criteria that can only be assessed in person.","TWN":"而且，這裡面還有一些是只有來現場才能評估的類型。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 학회 사람들은 참 한결같네.","JPN":"ふーん、学会の人たちって本当変わらないわね。","ENG":"Hmm... You Society people are all the same.","TWN":"嗯，學會的人還真是始終如一啊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"보고드립니다, 소장님. 융합체들이 현장에서 침입자를 발견했습니다.","JPN":"ご報告いたします、所長。融合体たちが現場で侵入者を発見しました。","ENG":"Reporting, sir. The hybriders have spotted intruders at the scene.","TWN":"報告，所長。融合體在現場發現了入侵者。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L38_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"음? 침입자는 발견 즉시 사살하라고 하지 않았나?","JPN":"む？　侵入者は発見し次第射殺するように伝えておいたはずだが。","ENG":"Hmm? Didn't I say to kill any intruders on sight?","TWN":"嗯？我不是說過，一旦發現入侵者就立刻擊斃嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"예. 다만 문제가……","JPN":"はい。ただ問題が……","ENG":"Yes, sir. But the problem is...","TWN":"是，但問題是……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이 녀석들, 리플레이서 맞지? 대체 왜 이런 데 있는 거야?","JPN":"こいつら、リプレイサーだよね？　なんでこんなところにいるの？","ENG":"These are Replacers, right? What are they doing here?","TWN":"這些傢伙，是克隆集團的傢伙沒錯吧？他們到底為什麼會在這裡？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그, 금방이라도 달려들 분위기에요.","JPN":"す、すぐにでも飛びかかってきそうな雰囲気です。","ENG":"I-it looks like they'll attack us any second now...","TWN":"好…好像馬上就要撲上來的氣勢呢。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그러게 그냥 저런 인간 따위 버리고 도망쳤으면 됐잖아! 왜 구하겠다고 해서!","JPN":"だからあんな人間なんか放っておいて逃げたらよかったじゃん！　なんで助けるとか言い出すんだよ！","ENG":"Yeah, that's why I voted to leave that human behind and run! But you just had to save her!","TWN":"所以說啊，只要丟下那種人逃跑就行了！幹嘛要救他！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다기엔 자네도 도움 받은 처지 아니었나?","JPN":"それにしては君も助けられた立場ではなかったのか？","ENG":"But then again, didn't you receive help from her as well?","TWN":"這麼說的話，你不也是被幫助的人嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으윽, 아픈 데 걸고 넘어지긴…. 나라고 짐덩어리 신세가 마음에 들겠냐구.","JPN":"うぐっ、痛いとこ突きやがって……アタシだって荷物になりたかったわけじゃないもん。","ENG":"Ngh... Rubbing it where it still hurts, eh? Do you think I'd enjoy dragging everyone down with me?","TWN":"呃呃，你可真會戳人痛處……你以為我願意當累贅嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"으, 흐으으……","JPN":"う、ふううっ……","ENG":"N-ngh...","TWN":"呃，呃呃……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"투정 부리지 마세요, 루나. 저는 제가 옳다고 생각하는 일을 할 뿐입니다.","JPN":"駄々をこねないでください、ルナさん。私は自分が正しいと思ったことをするまでですわ。","ENG":"Stop your whining, Luna. I did what I thought was right.","TWN":"別發牢騷了，露娜。我只是做了我認為正確的事。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그리고 그렇게 다시 실패를 반복하시겠지.","JPN":"そしてまた同じように失敗を繰り返すだろう。","ENG":"And you will fail again doing so.","TWN":"而且，應該又會那樣重蹈覆轍吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"오랜만이구려, 부학회장.","JPN":"お久しぶりですな、副学会長。","ENG":"Long time no see, Vice President.","TWN":"好久不見，副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네. 융합체를 보고 당신부터 떠올랐죠. 하이드리히 소장.","JPN":"……はい。融合体を見てまずあなたが思い浮かびました。ハイドリヒ所長。","ENG":"...Yes. I knew it was your doing when I saw the hybriders, Chief Heydrich.","TWN":"……嗯，看到融合體，我就先想到你了，海德里希所長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 이런 식으로 마주치다니 아쉽게 됐네요, 부학회장님.","JPN":"ふふっ、このような形でお会いするとは残念ですね、副学会長。","ENG":"Heh. It's a shame we had to meet like this, Ms. Vice President.","TWN":"呵呵，很遺憾我們竟然以這種方式見面，副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그런데…… 루나 너는 왜 거기 있어?","JPN":"ところで……ルナ、あなたはどうしてそこにいるのかしら。","ENG":"However... Luna? Why are you over there?","TWN":"不過……露娜，你為什麼在那兒？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"읏……","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"루나 님……?","JPN":"ルナ様……？","ENG":"Ms. Luna...?","TWN":"露娜……？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>님</color>?","JPN":"<color=#ffd34c>様</color>？","ENG":"<color=#ffd34c>Ms.</color>?","TWN":"<color=#ffd34c>露娜</color>？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아하, 또 눈치 없이 굴었나 보네. 하여간 바퀴벌레처럼 살아남는 재주 말고는 쓸모가 없다니까.","JPN":"なるほど、また余計なことしてたわけね。まったく、ゴキブリみたいに生き残る以外なんにもできないんだから。","ENG":"A-ha. You were acting clueless again. Then again, the only thing you're good at is surviving like a cockroach.","TWN":"啊哈，看來我出現的不是時候。總之，你除了像蟑螂一樣頑強的生存能力外，還真是一無是處。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아니야. 셰나. 나는 그냥…… 네가 시킨 대로……","JPN":"ち、違うよ。シェナ。アタシはただ……あんたが言ったとおりに……","ENG":"N-no. That's not it, Shena... I... I just did what you told me t–","TWN":"不，不是的，世娜。我就是……按照你的吩咐……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"부학회장님이 요양하는 동안 잘 감시하고 있으라고 했지, 누가 연락도 없이 졸졸 따라다니라고 했어?","JPN":"私は副学会長が療養している間、ちゃんと監視してって言ったはずよ。連絡もなしに後を付いて回れなんて一言も言ってないわ。","ENG":"I told you to keep an eye on her while she was recuperating. Who told you to follow her around without contacting me?","TWN":"我說過讓你在副學會長休養期間好好監視她，可沒讓你一聲不響就跟著她走吧？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"멍청하기 짝이 없네. 하긴 운 좋게 편입된 이교도 출신이었으니 어쩔 수 없으려나.","JPN":"つかえないにもほどがあるでしょ。まあ、運よく編入した異教徒出身なんて結局その程度かしら。","ENG":"Stupid little girl. Well, what can you do about a heretic who was lucky enough to be transferred to us?","TWN":"簡直愚蠢至極。也是，畢竟你是因為運氣好，才被編入樂團的異教徒，這也是沒辦法的事。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"우읏……","JPN":"ううっ……","ENG":"Urgh...","TWN":"嗚嗚……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐. 말씀이 너무 심하시네요.","JPN":"ちょっと。口がすぎますわ。","ENG":"Wait. How dare you talk to her like that?","TWN":"等一下，你這麼說太過分了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나가 아니었으면 전 여기 오지도 못했어요.","JPN":"ルナさんがいなかったら私はここへ来ることも叶いませんでした。","ENG":"If it was not for Luna, I would not have been able to come here.","TWN":"要不是露娜，我根本到不了這裡。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신들은 그런 식으로 동료를 폄하합니까?","JPN":"あなたたちはそのように仲間を貶すのですか？","ENG":"Do you always belittle your colleagues like this?","TWN":"你們就是用這種方式貶低同伴的嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"동료라니요, 부학회장님. 저런 건 그냥 대체품일 뿐이랍니다.","JPN":"仲間だなんてとんでもない、副学会長。あれはただの代替品です。","ENG":"\\"Colleague\\", Vice President? She is replaceable at any time.","TWN":"同伴嗎？副學會長，她只是替代品而已。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관악기에 결원이 생기는 바람에 운 좋게 발탁된 경우죠.","JPN":"管楽器に欠員ができて、運よく選ばれたケースですね。","ENG":"She is only here to replace one of our wind instrument members.","TWN":"因為樂團的管樂器出現了空缺，所以她才幸運地被提拔。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그런 주제에 어디 가서 자기가 최고라느니 떠들어대기나 하고…… 정말 겸손함을 모른다니까.","JPN":"そのくせに他で自分が最高だのなんだの騒いで……本当に謙遜というものを知らないわね。","ENG":"But blabbering on about being the best... She has no sense of humility.","TWN":"這種人居然好意思到處說自己是首席小號手……真是厚臉皮。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저 얘기에 귀 기울이지 마세요, 루나. 당신은 제가 아는 최고의 나팔수입니다.","JPN":"あの人の話に耳を傾けないでください、ルナさん。あなたは私が知る中で最高のトランぺッターです。","ENG":"Do not listen to her, Luna. You are the best trumpeter that I know.","TWN":"別把她的話放在心上，露娜。你就是我認識的首席小號手。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장님, 나, 나는 사실……","JPN":"副学会長。あ、アタシ、実は……","ENG":"Vice President... I-I'm actually...","TWN":"副學會長，我，其實我……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"루나, 지휘자님께서 기다리고 계셔.","JPN":"ルナ。マエストロがお待ちよ。","ENG":"Luna, Chief Conductor is waiting for you.","TWN":"露娜，指揮家在等你。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지... 지휘자님이?","JPN":"ま……マエストロが？","ENG":"Ch-chief Conductor?","TWN":"指……指揮家？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래. 지금이라도 고분고분하게 굴면 별다른 처벌은 내리지 않으실지도 모르지.","JPN":"そう。今からでも大人しく従えば、お咎めなしにしてくださるかもね。","ENG":"Yes. Perhaps, if you start behaving from now on, your wrongdoings will go unpunished.","TWN":"是的。你現在乖一點，說不定不會受到特別處罰。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 그간 네가 저질렀던 멍청한 짓들을 말씀드렸을 때도, 과연 널 받아들여 주실까?","JPN":"でも、ここに来るまでしでかした間抜けな行動の数々をお話しても、あなたのことを受け入れてくださるかしら？","ENG":"However, I wonder if she'll even take you back in once I tell her all the foolish stuff you've done.","TWN":"不過要是我把你這段時間幹的蠢事告訴指揮家，她真的會原諒你嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"루나 님, 설마 저 사람 말대로 하시려고요?","JPN":"ルナ様、まさかあの人の言うとおりにするおつもりですか？","ENG":"Ms. Luna, you're not thinking about doing as she says, right?","TWN":"露娜，你真的要按那個人說的做嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저희를…… 부학회장님을 도와 주실 수는 없는 건가요?","JPN":"私たちを……副学会長様を助けてはいただけないんですか？","ENG":"Can't you help us... No, I mean, the Vice President instead?","TWN":"不能……幫幫我們、幫幫副學會長嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"알잖아. 난 지금 아무 침식체랑 싸워도 질 만큼 약해.","JPN":"わかってるでしょ。アタシは今、その辺の侵食体と戦っても負けちゃうくらい弱いんだよ。","ENG":"You know, I'm too weak now that I cannot defeat any C.O.","TWN":"你也知道的，我現在弱到對上任何侵蝕體都會輸。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"죽고 싶지 않아. 부상이 금방 나아도 아픈 건 싫어……","JPN":"死にたくない。怪我がすぐ治っても痛いのはイヤだ……","ENG":"I don't wanna die. Even if my wounds may heal quickly, I don't wanna get hurt...","TWN":"我不想死，就算傷口癒合得很快，我也不喜歡疼……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그, 그러니까 미안……. 부학회장님.","JPN":"だ、だからごめん……副学会長。","ENG":"S-so... I'm sorry, Vice President.","TWN":"所…所以，對不起……副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰, 셰나도 부학회장님을 거칠게 대하진 않을 테니까! 응?","JPN":"しぇ、シェナも副学会長を乱暴に扱ったりはしないはずだから！　ね？","ENG":"A-and Shena promises not to be rough with the Vice President! Right?","TWN":"世…世娜不會粗魯地對待副學會長的！對不對？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런 표현은 자주 쓰지 않네만…… 완벽한 열세로군. 맥크레디 양.","JPN":"このような表現はあまり使わないのだが……完璧な劣勢だな。マクレディー君。","ENG":"I don't use this expression that much, but... We are completely at a disadvantage, Regina.","TWN":"雖然我不經常使用這種說法……不過你現在處於完美劣勢呢，麥克蕾蒂。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요, 사장님. 학회에 있는 동안 한 번도 우세했던 적은 없으니까.","JPN":"大丈夫ですわ、社長。学会にいる間、一度も優勢であったことなどありませんから。","ENG":"No need to worry, Boss. I have never been at an advantage during my stay at the Society.","TWN":"沒關係，老闆。因為我在學會裡從來就沒有過優勢。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"미리 말씀드리건대, 학회장께서 부학회장을 기다리고 계시오.","JPN":"先に言っておくが、学会長が副学会長をお待ちだ。","ENG":"To let you know ahead of time, Vice President, the President is expecting you.","TWN":"我先提醒你一句，副學會長，學會長在等你。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저 아이 말대로 굳이 부학회장께 위력을 행사할 이유는 없지.","JPN":"あの子の言うとおり、あえて副学会長に力を行使する理由はない。","ENG":"Like the child said, we have no reason to exert power over you.","TWN":"就像那孩子說的那樣，我們不必非得對副學會長動用武力。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지금 그 여자 앞에서 비켜만 주시면 에스코트를 해 드릴 용의도 있소만.","JPN":"今すぐその女の前からどいてさえくれれば、エスコートもしよう。","ENG":"If you step aside from that girl, I am willing to escort you to her.","TWN":"現在只要你讓開，我可以送你過去。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"사, 살려…… 살려 줘요…… 죽기 싫어…… 흐흑……","JPN":"た、助け……助けて……死にたくない……ううっ……","ENG":"S-save... Save me... I don't... want to die...","TWN":"救…救救……救救我……我不想死……嗚嗚……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……한 가지만 묻죠. 포로로 잡을 생각도 없나요?","JPN":"……一つだけお聞きしますわ。捕虜にするつもりもないのですか？","ENG":"...Let me ask you one question. Do you have no intention of taking her as a prisoner?","TWN":"……我就問你一個問題，你不想抓俘虜嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"평시라면 모를까, 최근에는 관리하기 어려울 만큼 소재가 들어와서 말이오.","JPN":"普段ならともかく、最近は管理に困るほどたくさんの素材が入ってきている。","ENG":"Normally, we would. However, we are facing difficulties with tons of material that came in recently.","TWN":"換作平時還有可能，只是最近收集的材料多到不好管理。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"특히 기관에 소속되어 있던 인간이라면 언제 사고를 칠지 모르니, 곤란하겠소.","JPN":"特に機関に所属していた人間ならいつ事故を起こすかわからないので、難しいな。","ENG":"Especially if they are agents of the Institution. We don't know what trouble they will cause.","TWN":"尤其是機關的人，說不定哪天就會闖禍，所以不好辦呐。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 그렇다면 저는 여기서 비킬 생각 없습니다.","JPN":"いいですわ。それなら私はここから動くつもりはありません。","ENG":"Very well. Then I will not be stepping aside.","TWN":"好吧，既然這樣，我就不打算讓開了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"물론 그러실 줄 알았소. 치기라는 것이 하루 아침에 사라지진 않는 법이지.","JPN":"もちろんそう来ると思っていた。稚気とは一晩で抜けるものではあるまい。","ENG":"I knew you would say that. Naivety is not something that can be eliminated overnight.","TWN":"我當然知道你會這麼做。因為孩子氣不會在一夜之間就消失。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자, 그럼 서류만으로는 확인할 수 없었던 성능을 다시 살펴 주셔야겠소이다.","JPN":"さて、では書類だけでは確認できなかったこの者たちの性能をもう一度試させてもらうか。","ENG":"Now then, it's time you saw what these soldiers can do that you couldn't see on the reports.","TWN":"那麼，就讓你親眼看看原本只能通過文件確認的這些武器的性能吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부디 냉철하게 평가해 주시오. 부학회장.","JPN":"どうか冷徹なご評価を。副学会長。","ENG":"If you will, please assess them as rationally as you can, Vice President.","TWN":"請你冷靜地給出評價，副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};